 22→/**
 23→ * 认证服务：处理 OAuth2 回调、用户查询
 24→ */
 25→@Slf4j
 26→@Service
 27→public class AuthService {
 28→
 29→    private final SysUserMapper sysUserMapper;
 30→    private final JwtUtil jwtUtil;
 31→    private final RestTemplate restTemplate;
 32→
 33→    @Value("${spring.security.oauth2.client.registration.default.client-id}")
 34→    private String clientId;
 35→
 36→    @Value("${spring.security.oauth2.client.registration.default.client-secret}")
 37→    private String clientSecret;
 38→
 39→    @Value("${spring.security.oauth2.client.provider.default.token-uri}")
 40→    private String tokenUri;
 41→
 42→    @Value("${spring.security.oauth2.client.provider.default.user-info-uri}")
 43→    private String userInfoUri;
 44→
 45→    @Value("${spring.security.oauth2.client.provider.default.authorization-uri}")
 46→    private String authorizationUri;
 47→
 48→    public AuthService(SysUserMapper sysUserMapper, JwtUtil jwtUtil) {
 49→        this.sysUserMapper = sysUserMapper;
 50→        this.jwtUtil = jwtUtil;
 51→        this.restTemplate = new RestTemplate();
 52→    }
 53→
 54→    /**
 55→     * 处理 OAuth2 回调：用 code 换 token，获取用户信息，同步到本地用户表，生成 JWT
 56→     *
 57→     * @param code         授权码
 58→     * @param redirectUri  回调地址（需与请求授权时一致）
 59→     * @return JWT token 字符串
 60→     */
 61→    public String handleOAuthCallback(String code, String redirectUri) {
 62→        // 1. 用 code 换 access_token
 63→        String accessToken = exchangeAccessToken(code, redirectUri);
 64→
 65→        // 2. 用 access_token 获取 OA 用户信息
 66→        Map<String, Object> oaUserInfo = fetchOaUserInfo(accessToken);
 67→        String oaUserId = (String) oaUserInfo.get("sub");
 68→        String username = (String) oaUserInfo.get("preferred_username");
 69→        String displayName = (String) oaUserInfo.get("name");
 70→
 71→        // 3. 按 oa_user_id 查库，有则更新，无则创建
 72→        SysUser user = sysUserMapper.selectOne(
 73→                new LambdaQueryWrapper<SysUser>().eq(SysUser::getOaUserId, oaUserId));
 74→
 75→        if (user != null) {
 76→            user.setUsername(username);
 77→            user.setDisplayName(displayName);
 78→            user.setUpdatedAt(LocalDateTime.now());
 79→            sysUserMapper.updateById(user);
 80→            log.info("[exam-auth] 用户登录(已存在), userId={}, oaUserId={}", user.getId(), oaUserId);
 81→        } else {
 82→            user = SysUser.builder()
 83→                    .oaUserId(oaUserId)
 84→                    .username(username)
 85→                    .displayName(displayName)
 86→                    .isAdmin(false)
 87→                    .createdAt(LocalDateTime.now())
 88→                    .updatedAt(LocalDateTime.now())
 89→                    .build();
 90→            sysUserMapper.insert(user);
 91→            log.info("[exam-auth] 用户首次登录(新建), userId={}, oaUserId={}", user.getId(), oaUserId);
 92→        }
 93→
 94→        // 4. 生成 JWT
 95→        return jwtUtil.generateToken(user.getId(), user.getIsAdmin());
 96→    }
 97→
 98→    /**
 99→     * 获取当前用户信息
100→     *
101→     * @param userId 用户 ID
102→     * @return 用户信息 DTO
103→     */
104→    public UserInfo getCurrentUser(Long userId) {
105→        SysUser user = sysUserMapper.selectById(userId);
106→        if (user == null) {
107→            throw new BizException(ErrorCode.NOT_FOUND);
108→        }
109→
110→        UserInfo info = new UserInfo();
111→        info.setId(user.getId());
112→        info.setOaUserId(user.getOaUserId());
113→        info.setUsername(user.getUsername());
114→        info.setDisplayName(user.getDisplayName());
115→        info.setIsAdmin(user.getIsAdmin());
116→        return info;
117→    }
118→
119→    /**
120→     * 用授权码换取 access_token
121→     */
122→    private String exchangeAccessToken(String code, String redirectUri) {
123→        HttpHeaders headers = new HttpHeaders();
124→        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);
125→        headers.setBasicAuth(clientId, clientSecret);
126→
127→        MultiValueMap<String, String> params = new LinkedMultiValueMap<>();
128→        params.add("grant_type", "authorization_code");
129→        params.add("code", code);
130→        params.add("redirect_uri", redirectUri);
131→
132→        HttpEntity<MultiValueMap<String, String>> request = new HttpEntity<>(params, headers);
133→
134→        ResponseEntity<Map<String, Object>> response = restTemplate.exchange(
135→                tokenUri,
136→                HttpMethod.POST,
137→                request,
138→                new ParameterizedTypeReference<>() {});
139→
140→        Map<String, Object> body = response.getBody();
141→        if (body == null || !body.containsKey("access_token")) {
142→            log.error("[exam-auth] 换取 access_token 失败, responseBody={}", body);
143→            throw new BizException(ErrorCode.INTERNAL_ERROR);
144→        }
145→        return (String) body.get("access_token");
146→    }
147→
148→    /**
149→     * 用 access_token 获取 OA 用户信息
150→     */
151→    private Map<String, Object> fetchOaUserInfo(String accessToken) {
152→        HttpHeaders headers = new HttpHeaders();
153→        headers.setBearerAuth(accessToken);
154→        HttpEntity<Void> request = new HttpEntity<>(headers);
155→
156→        ResponseEntity<Map<String, Object>> response = restTemplate.exchange(
157→                userInfoUri,
158→                HttpMethod.GET,
159→                request,
160→                new ParameterizedTypeReference<>() {});
161→
162→        Map<String, Object> body = response.getBody();
163→        if (body == null || !body.containsKey("sub")) {
164→            log.error("[exam-auth] 获取用户信息失败, responseBody={}", body);
165→            throw new BizException(ErrorCode.INTERNAL_ERROR);
166→        }
167→        return body;
168→    }
169→}
